import shutil
def task_func(path, delimiter="/"):
    if not isinstance(path, str) or not path.strip():
        raise ValueError("The 'path' must be a non-empty string.")

    if not os.path.exists(path):
        raise FileNotFoundError(f"The path '{path}' does not exist in the filesystem.")

    components = path.split(delimiter)
    if any(not component.strip() for component in components):
        raise ValueError("The 'path' contains invalid components (e.g., empty or whitespace-only).")

    result = []
    current_path = ""

    for component in components:
        current_path = os.path.join(current_path, component) if current_path else component

        if not os.path.exists(current_path):
            raise FileNotFoundError(f"The path component '{current_path}' does not exist in the filesystem.")

        usage = shutil.disk_usage(current_path)
        disk_usage = {
            "total": usage.total,
            "used": usage.used,
            "free": usage.free
        }

        result.append((component, disk_usage))

    return result

import re
import json
from collections import Counter
def task_func(json_str, top_n=10):
    pattern = r'(https?:\/\/(?:www\.|(?!www))[a-zA-Z0-9][a-zA-Z0-9-]+[a-zA-Z0-9]\.[^\s]{2,}|www\.[a-zA-Z0-9][a-zA-Z0-9-]+[a-zA-Z0-9]\.[^\s]{2,}|https?:\/\/(?:www\.|(?!www))[a-zA-Z0-9]+\.[^\s]{2,}|www\.[a-zA-Z0-9]+\.[^\s]{2,})'
    data = json.loads(json_str)
    urls = []

    def extract(dictionary):
        for key, value in dictionary.items():
            if isinstance(value, dict):
                extract(value)
            elif isinstance(value, str) and re.match(pattern, value):
                urls.append(value)

    extract(data)
    if not urls:
        return {}
    elif len(urls) <= top_n:
        return dict(Counter(urls))

    return dict(Counter(urls).most_common(top_n))

