import re
import random
def task_func(csv_file, column_name='data', pattern=r'\d+[xX]', sample_size=None, seed=42):
    try:
        df = pd.read_csv(csv_file)
    except Exception as e:
        raise ValueError(f"Error reading the CSV file: {e}")

    if column_name not in df.columns:
        raise ValueError(f"Column '{column_name}' not found in the CSV file.")

    try:
        matches = df[df[column_name].astype(str).str.contains(pattern, flags=re.IGNORECASE, regex=True)]
    except Exception as e:
        raise ValueError(f"Error applying regex pattern: {e}")

    if sample_size is not None:
        if sample_size <= 0:
            raise ValueError("sample_size must be a positive integer.")
        if sample_size > len(matches):
            raise ValueError("sample_size cannot be greater than the number of matches.")

        random.seed(seed)

        random_indices = random.sample(range(len(matches)), sample_size)

        return matches.iloc[random_indices]

    return matches

